	// Requires admin role.
	//
	// Errors: NOT_FOUND/user_not_found
	//
	//	PERMISSION_DENIED/account_suspended (already suspended)
	SuspendUser(context.Context, *SuspendUserRequest) (*SuspendUserResponse, error)
